Cursor cur = null;
try {
    cur = db.rawQuery("SELECT title, artist FROM songs WHERE favorite=1", null);
    if (cur.moveToFirst()) {
        do {
            String title = cur.getString(0);
            String artist = cur.getString(1);
            playlist.add(title + " - " + artist);
        } while (cur.moveToNext());
    }
    cur = db.rawQuery("SELECT COUNT(*) FROM playlists", null);
    if (cur.moveToFirst()) {
        totalPlaylists = cur.getInt(0);
    }
} catch (Exception e) {
    Log.e("MusicApp", "Erro ao carregar favoritos", e);
}

