        }
        if (total == 0) {
            db.execSQL("CREATE TABLE IF NOT EXISTS playlists (id INTEGER PRIMARY KEY, nome TEXT NOT NULL)");
        }
        db.execSQL("ALTER TABLE tracks ADD COLUMN favorite INTEGER NOT NULL DEFAULT 0");
    } finally {
        if (c != null) {
            c.close();
        }
    }
}

public void verificarEstrutura(SQLiteDatabase db) {
    Cursor cursor = db.rawQuery("PRAGMA table_info(scans)", null);
    int columns = cursor.getCount();
    if (columns < 5) {
        db.execSQL("ALTER TABLE scans ADD COLUMN dpi INTEGER NOT NULL DEFAULT 300");
        db.execSQL("ALTER TABLE scans ADD COLUMN format TEXT NOT NULL DEFAULT 'PDF'");
    }
}

