public void validarCategorias(SQLiteDatabase db) {
    Cursor c = db.rawQuery("SELECT name FROM sqlite_master WHERE type='table' AND name='articles'", null);
    if (c.getCount() == 0) {
        db.execSQL("CREATE TABLE IF NOT EXISTS articles (id INTEGER PRIMARY KEY, title TEXT NOT NULL)");
    } else {
        db.execSQL("ALTER TABLE articles ADD COLUMN source TEXT NOT NULL DEFAULT 'unknown'");
    }
}

