public void migraDados(SQLiteDatabase db) {
    Cursor c = db.rawQuery("SELECT * FROM transactions WHERE status='PENDING'", null);
    int pending = c.getCount();
    if (pending > 0) {
        db.execSQL("UPDATE transactions SET reviewed=1 WHERE status='PENDING'");
    }
    db.execSQL("ALTER TABLE transactions ADD COLUMN category TEXT DEFAULT 'misc'");
}

