import android.app.ListActivity;
import android.database.Cursor;
import android.os.AsyncTask;
import android.provider.MediaStore;
import android.text.TextUtils;
import android.widget.ArrayAdapter;
import android.widget.ListView;
import android.widget.Spinner;
import android.widget.TextView;

public class AlbumBrowserActivity extends ListActivity {
    private Spinner mGenreSpinner;
    private Cursor mCursor;

    private void loadGenres() {
        new AsyncTask<Void, Void, String[]>() {
            @Override
            protected String[] doInBackground(Void... params) {
                Cursor genreCursor = getContentResolver().query(
                        MediaStore.Audio.Genres.EXTERNAL_CONTENT_URI,
                        new String[]{MediaStore.Audio.Genres._ID, MediaStore.Audio.Genres.NAME},
                        null,
                        null,
                        MediaStore.Audio.Genres.NAME + " ASC");
                java.util.ArrayList<String> genres = new java.util.ArrayList<>();
                while (genreCursor.moveToNext()) {
                    String name = genreCursor.getString(1);
                    if (!TextUtils.isEmpty(name) && !genres.contains(name)) {
                        genres.add(name);
                    }
                }
                return genres.toArray(new String[0]);
            }

            @Override
            protected void onPostExecute(String[] result) {
                ArrayAdapter<String> adapter = new ArrayAdapter<>(AlbumBrowserActivity.this, android.R.layout.simple_spinner_item, result);
                adapter.setDropDownViewResource(android.R.layout.simple_spinner_dropdown_item);
                mGenreSpinner.setAdapter(adapter);
            }
        }.execute();
    }

    private void refreshAlbums(String genre) {
        mCursor = getContentResolver().query(
                MediaStore.Audio.Media.EXTERNAL_CONTENT_URI,
                new String[]{MediaStore.Audio.Media._ID, MediaStore.Audio.Media.ALBUM},
                MediaStore.Audio.Media.IS_MUSIC + "=1",
                new String[]{genre},
                MediaStore.Audio.Media.ALBUM + " ASC");
        setListAdapter(new android.widget.SimpleCursorAdapter(
                this,
                android.R.layout.simple_list_item_1,
                mCursor,
                new String[]{MediaStore.Audio.Media.ALBUM},
                new int[]{android.R.id.text1},
                0));
    }
}

import android.app.ListActivity;
import android.database.Cursor;
import android.os.AsyncTask;
import android.provider.MediaStore;
import android.text.TextUtils;
import android.widget.ArrayAdapter;
import android.widget.ListView;
import android.widget.Spinner;
import android.widget.TextView;

public class AlbumBrowserActivity extends ListActivity {
    private Spinner mGenreSpinner;
    private Cursor mCursor;

    private void loadGenres() {
        new AsyncTask<Void, Void, String[]>() {
            @Override
            protected String[] doInBackground(Void... params) {
                Cursor genreCursor = null;
                try {
                    genreCursor = getContentResolver().query(
                            MediaStore.Audio.Genres.EXTERNAL_CONTENT_URI,
                            new String[]{MediaStore.Audio.Genres._ID, MediaStore.Audio.Genres.NAME},
                            null,
                            null,
                            MediaStore.Audio.Genres.NAME + " ASC");
                    java.util.ArrayList<String> genres = new java.util.ArrayList<>();
                    if (genreCursor != null) {
                        while (genreCursor.moveToNext()) {
                            String name = genreCursor.getString(1);
                            if (!TextUtils.isEmpty(name) && !genres.contains(name)) {
                                genres.add(name);
                            }
                        }
                    }
                    return genres.toArray(new String[0]);
                } finally {
                    if (genreCursor != null) genreCursor.close();
                }
            }

            @Override
            protected void onPostExecute(String[] result) {
                ArrayAdapter<String> adapter = new ArrayAdapter<>(AlbumBrowserActivity.this, android.R.layout.simple_spinner_item, result);
                adapter.setDropDownViewResource(android.R.layout.simple_spinner_dropdown_item);
                mGenreSpinner.setAdapter(adapter);
            }
        }.execute();
    }

    private void refreshAlbums(String genre) {
        if (mCursor != null) mCursor.close();
        mCursor = getContentResolver().query(
                MediaStore.Audio.Media.EXTERNAL_CONTENT_URI,
                new String[]{MediaStore.Audio.Media._ID, MediaStore.Audio.Media.ALBUM},
                MediaStore.Audio.Media.IS_MUSIC + "=1",
                new String[]{genre},
                MediaStore.Audio.Media.ALBUM + " ASC");
        setListAdapter(new android.widget.SimpleCursorAdapter(
                this,
                android.R.layout.simple_list_item_1,
                mCursor,
                new String[]{MediaStore.Audio.Media.ALBUM},
                new int[]{android.R.id.text1},
                0));
    }
}

