import android.app.Activity;
import android.database.Cursor;
import android.os.AsyncTask;
import android.provider.BaseColumns;
import android.widget.ArrayAdapter;
import android.widget.Spinner;

public class LibraryFilterActivity extends Activity {
    private Spinner mAuthorSpinner;

    private void loadAuthors() {
        new AsyncTask<Void, Void, String[]>() {
            @Override
            protected String[] doInBackground(Void... params) {
                Cursor cursor = getContentResolver().query(
                        BooksContract.Authors.CONTENT_URI,
                        new String[]{BaseColumns._ID, BooksContract.Authors.COLUMN_NAME},
                        null,
                        null,
                        BooksContract.Authors.COLUMN_NAME + " ASC");
                java.util.ArrayList<String> authors = new java.util.ArrayList<>();
                if (cursor.moveToFirst()) {
                    do {
                        authors.add(cursor.getString(1));
                    } while (cursor.moveToNext());
                }
                return authors.toArray(new String[0]);
            }

            @Override
            protected void onPostExecute(String[] result) {
                mAuthorSpinner.setAdapter(new ArrayAdapter<>(LibraryFilterActivity.this, android.R.layout.simple_spinner_item, result));
            }
        }.execute();
    }
}

