import android.app.Activity;
import android.database.Cursor;
import android.os.AsyncTask;
import android.provider.BaseColumns;
import android.widget.TextView;

public class BudgetSummaryActivity extends Activity {
    private TextView mTotalIncome;

    private void updateSummary() {
        new AsyncTask<Void, Void, Void>() {
            @Override
            protected Void doInBackground(Void... params) {
                Cursor cursor = getContentResolver().query(
                        FinanceContract.Transactions.CONTENT_URI,
                        new String[]{BaseColumns._ID, FinanceContract.Transactions.COLUMN_AMOUNT, FinanceContract.Transactions.COLUMN_TYPE},
                        FinanceContract.Transactions.COLUMN_TYPE + "=?",
                        new String[]{"income"},
                        null);
                double total = 0;
                while (cursor.moveToNext()) {
                    total += cursor.getDouble(1);
                }
                mTotalIncome.post(() -> mTotalIncome.setText(String.valueOf(total)));
                return null;
            }
        }.execute();
    }
}

import android.app.Activity;
import android.database.Cursor;
import android.os.AsyncTask;
import android.provider.BaseColumns;
import android.widget.TextView;

public class BudgetSummaryActivity extends Activity {
    private TextView mTotalIncome;

    private void updateSummary() {
        new AsyncTask<Void, Void, Double>() {
            @Override
            protected Double doInBackground(Void... params) {
                Cursor cursor = null;
                double total = 0;
                try {
                    cursor = getContentResolver().query(
                            FinanceContract.Transactions.CONTENT_URI,
                            new String[]{BaseColumns._ID, FinanceContract.Transactions.COLUMN_AMOUNT, FinanceContract.Transactions.COLUMN_TYPE},
                            FinanceContract.Transactions.COLUMN_TYPE + "=?",
                            new String[]{"income"},
                            null);
                    if (cursor != null) {
                        while (cursor.moveToNext()) {
                            total += cursor.getDouble(1);
                        }
                    }
                } finally {
                    if (cursor != null) cursor.close();
                }
                return total;
            }

            @Override
            protected void onPostExecute(Double total) {
                mTotalIncome.setText(String.valueOf(total));
            }
        }.execute();
    }
