import android.database.Cursor;
import android.os.AsyncTask;
import android.provider.Telephony;
import android.widget.ListView;
import android.widget.SimpleCursorAdapter;

public class ConversationListActivity extends Activity {
    private Cursor mCursor;
    private ListView mListView;

    private void loadConversations() {
        new AsyncTask<Void, Void, Cursor>() {
            @Override
            protected Cursor doInBackground(Void... params) {
                return getContentResolver().query(
                        Telephony.Sms.Conversations.CONTENT_URI,
                        new String[]{Telephony.Sms.Conversations._ID, Telephony.Sms.Conversations.SNIPPET},
                        null,
                        null,
                        Telephony.Sms.Conversations.DATE + " DESC");
            }

            @Override
            protected void onPostExecute(Cursor cursor) {
                mCursor = cursor;
                mListView.setAdapter(new SimpleCursorAdapter(
                        ConversationListActivity.this,
                        android.R.layout.simple_list_item_1,
                        mCursor,
                        new String[]{Telephony.Sms.Conversations.SNIPPET},
                        new int[]{android.R.id.text1},
                        0));
            }
        }.execute();
    }
}

import android.app.Activity;
import android.database.Cursor;
import android.os.AsyncTask;
import android.provider.Telephony;
import android.widget.ListView;
import android.widget.SimpleCursorAdapter;

public class ConversationListActivity extends Activity {
    private Cursor mCursor;
    private ListView mListView;

    private void loadConversations() {
        new AsyncTask<Void, Void, Cursor>() {
            @Override
            protected Cursor doInBackground(Void... params) {
                return getContentResolver().query(
                        Telephony.Sms.Conversations.CONTENT_URI,
                        new String[]{Telephony.Sms.Conversations._ID, Telephony.Sms.Conversations.SNIPPET},
                        null,
                        null,
                        Telephony.Sms.Conversations.DATE + " DESC");
            }

            @Override
            protected void onPostExecute(Cursor cursor) {
                if (mCursor != null) mCursor.close();
                mCursor = cursor;
                mListView.setAdapter(new SimpleCursorAdapter(
                        ConversationListActivity.this,
                        android.R.layout.simple_list_item_1,
                        mCursor,
                        new String[]{Telephony.Sms.Conversations.SNIPPET},
                        new int[]{android.R.id.text1},
                        0));
            }
        }.execute();
    }

    @Override
    protected void onDestroy() {
        if (mCursor != null) mCursor.close();
        super.onDestroy();
    }
}

public List<Song> loadRecentSongs(Context context) {
    List<Song> songs = new ArrayList<>();
    Cursor cursor = context.getContentResolver().query(
            MediaStore.Audio.Media.EXTERNAL_CONTENT_URI,
            new String[]{MediaStore.Audio.Media._ID, MediaStore.Audio.Media.TITLE},
            null,
            null,
            MediaStore.Audio.Media.DATE_ADDED + " DESC");
    if (cursor != null) {
        while (cursor.moveToNext()) {
            songs.add(new Song(cursor.getLong(0), cursor.getString(1)));
        }
    }
    return songs;
}

