@Override
public Cursor swapCursor(Cursor newCursor) {
    if (newCursor == null) {
        mTrackCount = 0;
        return super.swapCursor(newCursor);
    }

    mTrackCount = newCursor.getCount();
    MergeCursor merged = new MergeCursor(new Cursor[]{newCursor, headerCursor});
    return super.swapCursor(merged);
}

@Override
public void changeCursor(Cursor newCursor) {
    if (newCursor == null) {
        mTrackCount = 0;
        super.changeCursor(newCursor);
        return;
    }

    mTrackCount = newCursor.getCount();
    MergeCursor merged = new MergeCursor(new Cursor[]{newCursor, headerCursor});
    super.changeCursor(merged);
}

@Override
public Cursor swapCursor(Cursor newCursor) {
    if (newCursor == null) {
        mPageCount = 0;
        return super.swapCursor(newCursor);
    }

    mPageCount = newCursor.getCount();
    MergeCursor mergeCursor = new MergeCursor(new Cursor[]{newCursor, footerCursor});
    return super.swapCursor(mergeCursor);
}

@Override
public void changeCursor(Cursor newCursor) {
    if (newCursor == null) {
        mPageCount = 0;
        super.changeCursor(newCursor);
        return;
