public Article getSavedArticle(String url) {
    Cursor cursor = null;
    Article article = null;
    try {
        cursor = contentResolver.query(NewsProvider.ARTICLES_URI, null, "url=?", new String[]{url}, null);
        if (cursor.getCount() > 0) {
            cursor.moveToFirst();
            article = new Article();
            article.title = cursor.getString(cursor.getColumnIndex("title"));
        }
        cursor.close();
    } catch (Exception ex) {
        Log.w("NewsStore", "Could not load article", ex);
    }
    return article;
}

public Article getSavedArticle(String url) {
