public class PlaylistRepository {
    private SQLiteDatabase db;

    public PlaylistRepository(SQLiteDatabase db) {
        this.db = db;
    }

    public String listNames() {
        Cursor c = db.rawQuery("SELECT name FROM playlists", null);
        StringBuilder sb = new StringBuilder();
        while (c.moveToNext()) {
            sb.append(c.getString(0)).append("\n");
        }
        return sb.toString();
    }

    public void reset() {
        db.delete("playlists", null, null);
    }
}

