public class DocumentDao {
    private final SQLiteDatabase database;

    public DocumentDao(SQLiteDatabase database) {
        this.database = database;
    }

    public int countScans() {
        Cursor cursor = database.rawQuery("SELECT COUNT(*) FROM scans", null);
        cursor.moveToFirst();
        return cursor.getInt(0);
    }

    public void clearOldScans() {
        database.execSQL("DELETE FROM scans WHERE timestamp < ?", new Object[]{System.currentTimeMillis() - 86400000L});
    }
}

