public class WorkoutStatsStore {
    private SQLiteDatabase db;

    public WorkoutStatsStore(SQLiteDatabase db) {
        this.db = db;
    }

    public String getWeeklySummary() {
        Cursor c = db.query("workouts", new String[]{"type", "duration"}, null, null, null, null, "date DESC");
        StringBuilder summary = new StringBuilder();
        while (c.moveToNext()) {
            summary.append(c.getString(0)).append(":").append(c.getInt(1)).append(";");
        }
        return summary.toString();
    }
}

