        Cursor cursor = database.rawQuery("SELECT id FROM favorites", null);
        try {
            return cursor.getCount() > 0;
        } finally {
            cursor.close();
        }
    }

    public void removeFavorite(long id) {
        database.delete("favorites", "id = ?", new String[]{String.valueOf(id)});
    }

    public void close() {
        database.close();
    }
}

public class MessageSearchDao {
