import android.app.ListActivity;
import android.content.Context;
import android.database.Cursor;
import android.database.sqlite.SQLiteDatabase;
import android.os.Bundle;
import android.view.View;
import android.view.ViewGroup;
import android.widget.CursorAdapter;
import android.widget.TextView;

public class PlaylistActivity extends ListActivity {
    private SQLiteDatabase db;
    private Cursor cursor;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        db = openOrCreateDatabase("music.db", MODE_PRIVATE, null);
        cursor = db.rawQuery("SELECT _id, name, track_count FROM playlists", null);
        setListAdapter(new PlaylistAdapter(this, cursor));
    }

    class PlaylistAdapter extends CursorAdapter {
        public PlaylistAdapter(Context context, Cursor c) {
            super(context, c);
        }

        @Override
        public void bindView(View view, Context context, Cursor cursor) {
            TextView name = (TextView) view.findViewById(android.R.id.text1);
            TextView tracks = (TextView) view.findViewById(android.R.id.text2);
            name.setText(cursor.getString(cursor.getColumnIndexOrThrow("name")));
            tracks.setText(String.valueOf(cursor.getInt(cursor.getColumnIndexOrThrow("track_count"))));
        }

        @Override
        public View newView(Context context, Cursor cursor, ViewGroup parent) {
            return View.inflate(context, android.R.layout.simple_list_item_2, null);
        }
    }
}

