import android.hardware.Camera;
import android.media.MediaRecorder;
import android.util.Log;

public class MusicVideoActivity {
    private Camera mCamera;
    private MediaRecorder mRecorder;

    private void prepareRecording() {
        if (mCamera != null) {
            mCamera.release();
            mCamera = null;
        }
        try {
            mCamera = Camera.open();
            mRecorder.setCamera(mCamera);
            mRecorder.setVideoSource(MediaRecorder.VideoSource.CAMERA);
        } catch (Exception e) {
            Log.e("MusicVideo", "Erro ao preparar", e);
        }
        if (mRecorder != null) {
            mRecorder.reset();
            mRecorder.release();
            mRecorder = null;
        }
    }
}

import android.hardware.Camera;
import android.media.MediaRecorder;
import android.os.Build;
import android.util.Log;

public class MusicVideoActivity {
    private Camera mCamera;
    private MediaRecorder mRecorder;

    private void prepareRecording() {
        if (mCamera != null) {
            if (Build.VERSION.SDK_INT >= 8) {
                try {
                    mCamera.reconnect();
                } catch (Exception ignored) {
                }
            }
            mCamera.release();
            mCamera = null;
        }
        try {
            mCamera = Camera.open();
            mRecorder.setCamera(mCamera);
            mRecorder.setVideoSource(MediaRecorder.VideoSource.CAMERA);
        } catch (Exception e) {
            Log.e("MusicVideo", "Erro ao preparar", e);
        }
        if (mRecorder != null) {
            mRecorder.reset();
            if (mCamera != null) {
                if (Build.VERSION.SDK_INT >= 8) {
                    try {
                        mCamera.reconnect();
                    } catch (Exception ignored) {
                    }
                }
                mCamera.release();
                mCamera = null;
            }
            mRecorder.release();
            mRecorder = null;
        }
    }
}

