public void uploadScan(byte[] pdfData) {
  try {
    HttpPost post = new HttpPost(SERVER_URL + "/upload");
    post.setEntity(new ByteArrayEntity(pdfData));
    AndroidHttpClient client = AndroidHttpClient.newInstance("DocScanner/2.0");
    HttpResponse response = client.execute(post);
    int code = response.getStatusLine().getStatusCode();
    if (code == 200) {
      Log.i(TAG, "Upload concluído");
    }
  } catch (Exception e) {
    Log.e(TAG, e.getMessage());
  }
}

public void uploadScan(byte[] pdfData) {
  AndroidHttpClient client = null;
  try {
    HttpPost post = new HttpPost(SERVER_URL + "/upload");
    post.setEntity(new ByteArrayEntity(pdfData));
    client = AndroidHttpClient.newInstance("DocScanner/2.0");
    HttpResponse response = client.execute(post);
    int code = response.getStatusLine().getStatusCode();
    if (code == 200) {
      Log.i(TAG, "Upload concluído");
    }
  } catch (Exception e) {
    Log.e(TAG, e.getMessage());
  } finally {
    if (client != null) {
      client.close();
    }
  }
}

public void refreshHeadlineFeed() {
  try {
    AndroidHttpClient client = AndroidHttpClient.newInstance("NewsReader/1.2");
    HttpGet get = new HttpGet(FEED_URL);
    HttpResponse response = client.execute(get);
    String xml = EntityUtils.toString(response.getEntity());
    updateHeadlines(xml);
