private WifiManager.WifiLock wifiLock = null;
private boolean streaming = false;
private int reconnectAttempts = 0;

public void startPlayback(String streamUrl) {
    wifiLock = wifiManager.createWifiLock(WifiManager.WIFI_MODE_FULL_HIGH_PERF, "MusicStreamLock");
    wifiLock.acquire();
    streaming = true;
    reconnectAttempts++;
    player.connect(streamUrl);
}

public void onPlaybackStopped() {
    streaming = false;
    player.stop();
}

