public void startWorkoutSession(final Context context, final WorkoutPlan plan) {
    PowerManager pm = (PowerManager) context.getSystemService(Context.POWER_SERVICE);
    WakeLock wakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "Fitness:WorkoutSession");
    wakeLock.setReferenceCounted(false);
    wakeLock.acquire();

    timer.start(plan.getDurationMillis(), new TimerCallback() {
        @Override
        public void onTick(long remaining) {
            workoutListener.onProgress(remaining);
        }

        @Override
        public void onFinish() {
            workoutListener.onWorkoutCompleted();
        }
    });
}

public void startWorkoutSession(final Context context, final WorkoutPlan plan) {
    PowerManager pm = (PowerManager) context.getSystemService(Context.POWER_SERVICE);
    final WakeLock wakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "Fitness:WorkoutSession");
    wakeLock.setReferenceCounted(false);
    wakeLock.acquire();

    timer.start(plan.getDurationMillis(), new TimerCallback() {
        @Override
        public void onTick(long remaining) {
            workoutListener.onProgress(remaining);
        }

        @Override
        public void onFinish() {
            try {
                workoutListener.onWorkoutCompleted();
            } finally {
                if (wakeLock.isHeld()) {
                    wakeLock.release();
                }
            }
        }
    });
}

public void beginTurnByTurnNavigation(final Context context, final Route route) {
    PowerManager pm = (PowerManager) context.getSystemService(Context.POWER_SERVICE);
    WakeLock wakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "Navigator:RouteTracking");
    wakeLock.setReferenceCounted(false);
    wakeLock.acquire(20 * 60 * 1000L);

    locationManager.requestLocationUpdates(route.getProvider(), 1000L, 5f, locationListener);
    routeUpdater.start(route, new Runnable() {
        @Override
        public void run() {
            ui.showNavigationRunning();
        }
    });
}

