public void bufferAndPlay(final Context context, final String videoId) {
    PowerManager pm = (PowerManager) context.getSystemService(Context.POWER_SERVICE);
    WakeLock wakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "VideoPlayer:Buffer");
    wakeLock.setReferenceCounted(false);
    wakeLock.acquire(30 * 60 * 1000L);

    networkFetcher.fetch(videoId, new FetchCallback() {
        @Override
        public void onResponse(VideoStream stream) {
            player.setStream(stream);
            player.play();
        }
    });
}

public void bufferAndPlay(final Context context, final String videoId) {
    PowerManager pm = (PowerManager) context.getSystemService(Context.POWER_SERVICE);
    final WakeLock wakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "VideoPlayer:Buffer");
    wakeLock.setReferenceCounted(false);
    wakeLock.acquire(30 * 60 * 1000L);

    networkFetcher.fetch(videoId, new FetchCallback() {
        @Override
        public void onResponse(VideoStream stream) {
            try {
                player.setStream(stream);
                player.play();
            } finally {
                if (wakeLock.isHeld()) {
                    wakeLock.release();
                }
            }
        }

        @Override
        public void onFailure(Throwable t) {
            try {
                errorHandler.handle(t);
            } finally {
                if (wakeLock.isHeld()) {
                    wakeLock.release();
                }
            }
        }
    });
}

