public void sendQueuedMessages(final Context context, final List<Message> queue) {
    PowerManager pm = (PowerManager) context.getSystemService(Context.POWER_SERVICE);
    WakeLock wakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "Messenger:QueueSend");
    wakeLock.setReferenceCounted(false);
    wakeLock.acquire(60 * 1000L);

    messageSender.send(queue, new SendCallback() {
        @Override
        public void onComplete() {
            ui.showToast("Messages sent");
        }
    });
}

public void sendQueuedMessages(final Context context, final List<Message> queue) {
    PowerManager pm = (PowerManager) context.getSystemService(Context.POWER_SERVICE);
    final WakeLock wakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "Messenger:QueueSend");
    wakeLock.setReferenceCounted(false);
    wakeLock.acquire(60 * 1000L);

    messageSender.send(queue, new SendCallback() {
        @Override
        public void onComplete() {
            try {
                ui.showToast("Messages sent");
            } finally {
                if (wakeLock.isHeld()) {
                    wakeLock.release();
                }
            }
        }

        @Override
        public void onError(Exception e) {
            try {
                ui.showError(e);
            } finally {
                if (wakeLock.isHeld()) {
                    wakeLock.release();
                }
            }
        }
    });
}

