        PowerManager pm = (PowerManager) getSystemService(Context.POWER_SERVICE);
        PowerManager.WakeLock wakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, TAG);
        wakeLock.acquire();
        try {
            if (intent != null && "reboot".equals(intent.getStringExtra("cmd"))) {
                rebootDevice();
                return;
            }

            sendStatusToCloud();
        } finally {
            if (wakeLock.isHeld()) {
                wakeLock.release();
            }
        }
    }

    private void rebootDevice() {}
    private void sendStatusToCloud() {}
}

