    mSyncRunnable = new SyncRunnable(conversationId);
    if (chatWakeLock == null) {
        chatWakeLock = powerManager.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "Chat:Sync");
    }
    chatWakeLock.acquire();
    syncHandler.postDelayed(mSyncRunnable, 3000);
}

if (pushSyncRequired) {
    if (mSyncRunnable != null) {
        syncHandler.removeCallbacks(mSyncRunnable);
        chatWakeLock.release(mSyncRunnable);
    }
    mSyncRunnable = new SyncRunnable(conversationId);
    if (chatWakeLock == null) {
        chatWakeLock = powerManager.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "Chat:Sync");
    }
    chatWakeLock.acquire();
    syncHandler.postDelayed(mSyncRunnable, 3000);
}

if (syncAnnotations) {
    if (mUploadTask != null) {
        mUploadTask.cancel();
    }
    mUploadTask = new AnnotationUploadTask(bookId);
    if (readerWakeLock == null) {
        readerWakeLock = powerManager.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "Reader:Sync");
    }
    readerWakeLock.acquire();
    asyncExecutor.submit(mUploadTask);
}

if (syncAnnotations) {
    if (mUploadTask != null) {
        mUploadTask.cancel();
        readerWakeLock.release(mUploadTask);
    }
    mUploadTask = new AnnotationUploadTask(bookId);
    if (readerWakeLock == null) {
        readerWakeLock = powerManager.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "Reader:Sync");
    }
    readerWakeLock.acquire();
    asyncExecutor.submit(mUploadTask);
}

public class PlayerActivity extends Activity {
    private PowerManager.WakeLock playWakeLock;
    private MediaPlayer mediaPlayer;

    private void startPlayback() {
        PowerManager pm = (PowerManager) getSystemService(POWER_SERVICE);
        playWakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "MusicApp:PlaybackLock");
        playWakeLock.acquire();
        mediaPlayer.start();
    }

    private void onTrackCompleted() {
        if (mediaPlayer != null) {
            mediaPlayer.release();
            mediaPlayer = null;
        }
        // BUG: wake lock is never released when playback finishes
    }
}

public class PlayerActivity extends Activity {
    private PowerManager.WakeLock playWakeLock;
    private MediaPlayer mediaPlayer;

    private void startPlayback() {
        PowerManager pm = (PowerManager) getSystemService(POWER_SERVICE);
        playWakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "MusicApp:PlaybackLock");
        playWakeLock.acquire();
        mediaPlayer.start();
    }

    private void onTrackCompleted() {
        if (mediaPlayer != null) {
            mediaPlayer.release();
            mediaPlayer = null;
        }
        if (playWakeLock != null && playWakeLock.isHeld()) {
            playWakeLock.release();
        }
    }
}

public class ScanService extends Service {
    private PowerManager.WakeLock scanWakeLock;
    private CameraDevice cameraDevice;

    public void beginScan() {
        PowerManager pm = (PowerManager) getSystemService(POWER_SERVICE);
        scanWakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "Scanner:ScanLock");
        scanWakeLock.acquire();
        openCamera();
    }

    private void onScanError(Throwable t) {
        closeCamera();
        // BUG: early exit without releasing wake lock on failure
        stopSelf();
    }

    private void closeCamera() {
        if (cameraDevice != null) {
            cameraDevice.close();
            cameraDevice = null;
        }
    }
}

public class ScanService extends Service {
    private PowerManager.WakeLock scanWakeLock;
    private CameraDevice cameraDevice;

    public void beginScan() {
        PowerManager pm = (PowerManager) getSystemService(POWER_SERVICE);
        scanWakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "Scanner:ScanLock");
        scanWakeLock.acquire();
        openCamera();
    }

    private void onScanError(Throwable t) {
        closeCamera();
        if (scanWakeLock != null && scanWakeLock.isHeld()) {
            scanWakeLock.release();
        }
        stopSelf();
    }

    private void closeCamera() {
        if (cameraDevice != null) {
            cameraDevice.close();
            cameraDevice = null;
        }
    }
}

public class WorkoutTracker extends Service {
    private PowerManager.WakeLock workoutWakeLock;
    private Handler handler = new Handler();

    public void startWorkout() {
        PowerManager pm = (PowerManager) getSystemService(POWER_SERVICE);
        workoutWakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "Fitness:WorkoutLock");
        workoutWakeLock.acquire();
        scheduleGpsUpdates();
    }

    public void onWorkoutPaused() {
        handler.removeCallbacksAndMessages(null);
        // BUG: wake lock kept alive while workout is paused
    }

    public void onDestroy() {
        handler.removeCallbacksAndMessages(null);
    }
}

public class WorkoutTracker extends Service {
    private PowerManager.WakeLock workoutWakeLock;
    private Handler handler = new Handler();

    public void startWorkout() {
        PowerManager pm = (PowerManager) getSystemService(POWER_SERVICE);
        workoutWakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "Fitness:WorkoutLock");
        workoutWakeLock.acquire();
        scheduleGpsUpdates();
    }

    public void onWorkoutPaused() {
        handler.removeCallbacksAndMessages(null);
        if (workoutWakeLock != null && workoutWakeLock.isHeld()) {
            workoutWakeLock.release();
        }
    }

    public void onDestroy() {
        handler.removeCallbacksAndMessages(null);
        if (workoutWakeLock != null && workoutWakeLock.isHeld()) {
            workoutWakeLock.release();
        }
    }
}

public class PodcastDownloadManager {
    private PowerManager.WakeLock downloadWakeLock;
    private ExecutorService executor;

    public void downloadEpisode() {
        PowerManager pm = (PowerManager) context.getSystemService(Context.POWER_SERVICE);
        downloadWakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "Podcast:DownloadLock");
        downloadWakeLock.acquire();
        executor.submit(() -> fetchFile());
    }

    private void onDownloadCancelled() {
        executor.shutdownNow();
        // BUG: cancellation path forgets to release wakelock
    }
}

public class PodcastDownloadManager {
    private PowerManager.WakeLock downloadWakeLock;
    private ExecutorService executor;

    public void downloadEpisode() {
        PowerManager pm = (PowerManager) context.getSystemService(Context.POWER_SERVICE);
        downloadWakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "Podcast:DownloadLock");
        downloadWakeLock.acquire();
        executor.submit(() -> fetchFile());
    }

    private void onDownloadCancelled() {
        executor.shutdownNow();
        if (downloadWakeLock != null && downloadWakeLock.isHeld()) {
            downloadWakeLock.release();
        }
    }
}

public class BackupWorker extends Worker {
    private PowerManager.WakeLock backupWakeLock;

    @NonNull
    @Override
    public Result doWork() {
        PowerManager pm = (PowerManager) getApplicationContext().getSystemService(Context.POWER_SERVICE);
        backupWakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "BackupApp:BackupLock");
        backupWakeLock.acquire();
        try {
            uploadPendingFiles();
            return Result.success();
        } catch (Exception e) {
            return Result.retry();
        }
    }
}

public class BackupWorker extends Worker {
    private PowerManager.WakeLock backupWakeLock;

    @NonNull
    @Override
    public Result doWork() {
        PowerManager pm = (PowerManager) getApplicationContext().getSystemService(Context.POWER_SERVICE);
        backupWakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "BackupApp:BackupLock");
        backupWakeLock.acquire();
        try {
            uploadPendingFiles();
            return Result.success();
        } catch (Exception e) {
            return Result.retry();
        } finally {
            if (backupWakeLock != null && backupWakeLock.isHeld()) {
                backupWakeLock.release();
            }
        }
    }
}

public class UploadController {
    private PowerManager.WakeLock uploadWakeLock;

    public void uploadAlbum() {
        PowerManager pm = (PowerManager) appContext.getSystemService(Context.POWER_SERVICE);
        uploadWakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "Gallery:UploadLock");
        uploadWakeLock.acquire();
        startMultipartUpload();
    }

    public void onServerResponse(boolean success) {
        if (success) {
            clearPendingQueue();
        } else {
            scheduleRetry();
        }
        // BUG: no release in either branch
    }
}

