public class RadioStreamManager {
    private PowerManager.WakeLock streamWakeLock;
    private AudioTrack audioTrack;

    public void startStream() {
        PowerManager pm = (PowerManager) context.getSystemService(Context.POWER_SERVICE);
        streamWakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "RadioApp:StreamLock");
        streamWakeLock.acquire();
        audioTrack.play();
    }

    public void handleBufferUnderrun() {
        audioTrack.pause();
        reconnectStream();
        if (streamWakeLock != null && streamWakeLock.isHeld()) {
            streamWakeLock.release();
        }
    }
}

