import java.io.IOException;
import java.io.InputStream;

class AudioStreamFactory {
    InputStream wrapAudioStream(InputStream rawInputStream, String codec) {
        if ("mp3".equals(codec)) {
            return new Mp3InputStream(rawInputStream);
        }
        if ("aac".equals(codec)) {
            return new AacInputStream(rawInputStream);
        }
        return rawInputStream;
    }
}

import java.io.IOException;
import java.io.InputStream;

class AudioStreamFactory {
    InputStream wrapAudioStream(final InputStream rawInputStream, String codec) {
        if ("mp3".equals(codec)) {
            return new Mp3InputStream(rawInputStream) {
                @Override
                public void close() throws IOException {
                    super.close();
                    rawInputStream.close();
                }
            };
        }
        if ("aac".equals(codec)) {
            return new AacInputStream(rawInputStream) {
                @Override
                public void close() throws IOException {
                    super.close();
                    rawInputStream.close();
                }
            };
        }
        return rawInputStream;
    }
}

import java.io.IOException;
import java.io.InputStream;

class DocumentDecoder {
    InputStream decode(InputStream source, String format) {
        if ("jpeg".equals(format)) {
            return new JpegDecodingInputStream(source);
        }
        if ("pdf".equals(format)) {
            return new PdfDecodingInputStream(source);
        }
        return source;
    }
}

import java.io.IOException;
import java.io.InputStream;

class DocumentDecoder {
    InputStream decode(final InputStream source, String format) {
        if ("jpeg".equals(format)) {
            return new JpegDecodingInputStream(source) {
                @Override
                public void close() throws IOException {
                    super.close();
                    source.close();
                }
            };
        }
        if ("pdf".equals(format)) {
            return new PdfDecodingInputStream(source) {
                @Override
                public void close() throws IOException {
                    super.close();
                    source.close();
                }
            };
        }
        return source;
    }
}

import java.io.IOException;
import java.io.InputStream;

class WorkoutDataParser {
    InputStream parse(InputStream input, String compression) {
        if ("gzip".equals(compression)) {
            return new GzipInputStream(input);
        }
        if ("deflate".equals(compression)) {
            return new DeflateInputStream(input);
        }
        return input;
    }
}

import java.io.IOException;
import java.io.InputStream;

class WorkoutDataParser {
    InputStream parse(final InputStream input, String compression) {
        if ("gzip".equals(compression)) {
            return new GzipInputStream(input) {
                @Override
                public void close() throws IOException {
                    super.close();
                    input.close();
                }
            };
        }
        if ("deflate".equals(compression)) {
            return new DeflateInputStream(input) {
                @Override
                public void close() throws IOException {
                    super.close();
                    input.close();
                }
            };
        }
        return input;
    }
}

import java.io.IOException;
import java.io.InputStream;

class ImagePipeline {
    InputStream prepare(InputStream source, String filter) {
        if ("thumbnail".equals(filter)) {
            return new ThumbnailInputStream(source);
        }
        if ("enhance".equals(filter)) {
            return new EnhanceInputStream(source);
        }
        return source;
    }
}

import java.io.IOException;
import java.io.InputStream;

class ImagePipeline {
    InputStream prepare(final InputStream source, String filter) {
        if ("thumbnail".equals(filter)) {
            return new ThumbnailInputStream(source) {
                @Override
                public void close() throws IOException {
                    super.close();
                    source.close();
                }
            };
        }
        if ("enhance".equals(filter)) {
            return new EnhanceInputStream(source) {
                @Override
                public void close() throws IOException {
                    super.close();
                    source.close();
                }
            };
        }
