public class FirmwareUpdater {
    public void applyUpdate(InputStream firmwareStream, OutputStream deviceStream) throws IOException {
        byte[] buffer = new byte[8192];
        int count;
        while ((count = firmwareStream.read(buffer)) != -1) {
            deviceStream.write(buffer, 0, count);
        }
        deviceStream.flush();
    }
}

public class FirmwareUpdater {
    public void applyUpdate(InputStream firmwareStream, OutputStream deviceStream) throws IOException {
        try {
            byte[] buffer = new byte[8192];
            int count;
            while ((count = firmwareStream.read(buffer)) != -1) {
                deviceStream.write(buffer, 0, count);
            }
            deviceStream.flush();
        } finally {
            try {
                firmwareStream.close();
            } catch (IOException ignored) {
            }
            try {
                deviceStream.close();
            } catch (IOException ignored) {
            }
        }
    }
}

