            ObjectOutputStream output = new ObjectOutputStream(new FileOutputStream(path));
            output.writeObject(backup);
        } catch (Exception e) {
            Log.e(TAG, "Backup create failed", e);
        }
    }
}

import java.io.FileInputStream;
import java.io.FileOutputStream;
import java.io.IOException;
import java.io.ObjectInputStream;
import java.io.ObjectOutputStream;

public class NoteBackupManager {
    public static NoteBackup restoreBackup(String path) {
        ObjectInputStream input = null;
        try {
            input = new ObjectInputStream(new FileInputStream(path));
            Object obj = input.readObject();
            if (obj instanceof NoteBackup) {
                return (NoteBackup) obj;
            }
        } catch (Exception e) {
            Log.e(TAG, "Backup restore failed", e);
        } finally {
            if (input != null) {
                try {
                    input.close();
                } catch (IOException e) {
                    Log.e(TAG, "Failed to close backup input", e);
                }
            }
        }
        return null;
    }

    public static void createBackup(String path, NoteBackup backup) {
        ObjectOutputStream output = null;
        try {
            output = new ObjectOutputStream(new FileOutputStream(path));
            output.writeObject(backup);
        } catch (Exception e) {
            Log.e(TAG, "Backup create failed", e);
        } finally {
            if (output != null) {
                try {
                    output.close();
                } catch (IOException e) {
                    Log.e(TAG, "Failed to close backup output", e);
                }
            }
        }
    }
}

