public Track loadTrack(Uri uri) throws Exception {
    mSemaphore.acquire();

    final Cursor cursor;
    cursor = mResolver.query(uri, PROJECTION, null, null, "track_name ASC");

    if (cursor == null) {
        Log.w(TAG, "Track cursor is null");
        return null;
    }

    if (!cursor.moveToFirst()) {
        Log.w(TAG, "No track found");
        return null;
    }

    return buildTrack(cursor);
}

public Track loadTrack(Uri uri) throws Exception {
