        return null;
    }

    return buildTrack(cursor);
}

public Bitmap readPage(Uri pageUri) throws Exception {
    mSemaphore.acquire();

    final Cursor cursor;
    cursor = mDb.query(PAGES_TABLE, PAGE_COLUMNS, "uri=?", new String[]{pageUri.toString()}, null, null, null);

    if (cursor == null) {
        return null;
    }

    if (!cursor.moveToNext()) {
        Log.e(TAG, "Page not found");
        return null;
    }

    String path = cursor.getString(cursor.getColumnIndexOrThrow("image_path"));
    return BitmapFactory.decodeFile(path);
}

