private void logNowPlaying(final Song song, final StringBuilder sb) {
    final Formatter formatter = new Formatter(sb);
    formatter.format("Now playing: %s - %s (%d sec)\n", song.getArtist(), song.getTitle(), song.getDurationSeconds());
    if (song.isFavorite()) {
        sb.append("[favorite]\n");
    }
}

