    final Formatter formatter = new Formatter(status);
    formatter.format("Order: %s\n", order.getOrderCode());
    formatter.format("Driver: %s\n", order.getDriverName());
    formatter.format("ETA: %d minutes\n", order.getEtaMinutes());
    if (order.isContactless()) {
        status.append("Contactless delivery\n");
    }
}

private void appendDeliveryStatus(final StringBuilder status, final DeliveryOrder order) {
    final Formatter formatter = new Formatter(status);
    formatter.format("Order: %s\n", order.getOrderCode());
    formatter.format("Driver: %s\n", order.getDriverName());
    formatter.format("ETA: %d minutes\n", order.getEtaMinutes());
    if (order.isContactless()) {
        status.append("Contactless delivery\n");
    }
    formatter.close();
}

